def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0 or item <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        base_score = 1.0
        decay = 0.97
        bonus = 0.0
        complex_penalty = 0.0
        weight = 1.0
        toggle = True
        for x in range(1, 15):
            if x % 4 == 0:
                base_score *= (1 + 0.03 * x) if toggle else (1 - 0.02 * x)
                toggle = not toggle
            if x % 7 == 0:
                base_score += np.tanh(ratio * x) * 5
            if cap % (x + 1) == 0 and (x * cap) % 5 == 0:
                bonus += np.exp(-abs(ratio - x/10)) * x
            if 0.1 < ratio < 0.9:
                base_score += (np.sin(ratio * x) ** 2) * 2 / (x + 1)
            else:
                base_score -= (np.cos(ratio * x)) * (x/10)
            if (cap + item) % (x + 3) == 0:
                complex_penalty += np.log1p(abs(cap - item) + x) / (x + 2)
            else:
                complex_penalty -= (x * np.sqrt(abs(cap - item))) / (x + 3)
            if x % 5 == 0:
                weight *= 1.05 if ratio < 0.5 else 0.95
            if x == 10:
                inner_sum = 0.0
                for y in range(1, 6):
                    diff = cap - item * y ** 1.5
                    if diff > 0:
                        inner_sum += np.sin(diff / (y+1)) * y
                    else:
                        inner_sum -= np.cos(abs(diff) / (y+2)) * (y/2)
                complex_penalty += inner_sum * 0.7
        final_score = base_score + bonus - complex_penalty
        if final_score < 0:
            priorities[i] = -final_score * (np.log1p(cap) + np.sqrt(item))
        else:
            if cap > item * 3:
                priorities[i] = -final_score / (np.sqrt(cap) + 1.5) * (1 + ratio**2)
            else:
                priorities[i] = -final_score / (cap + 2) * np.exp(-ratio)
        if ratio > 1:
            priorities[i] *= 1.2
        elif ratio < 0.1:
            priorities[i] *= 0.8
        if cap % 3 == 0:
            priorities[i] *= 0.95
        elif cap % 5 == 0:
            priorities[i] *= 1.1
        if abs(cap - item) < 2:
            priorities[i] *= 1.05
        elif abs(cap - item) > 10:
            priorities[i] *= 0.9
    return priorities
